queries.sparql:
PREFIX : <http://ambrosia.example.org/journalism#>
PREFIX p: <http://ambrosia.example.org/journalism/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?mission_name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasMissions ?child ; p:hasSpace_Reporters ?parent . } GROUP BY ?child }
  ?child p:mission_name ?mission_name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Space_Reporters } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/journalism#>
PREFIX p: <http://ambrosia.example.org/journalism/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  collective: { SELECT ?mission_name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasMissions ?child ; p:hasSpace_Reporters ?parent . } GROUP BY ?child }
  ?child p:mission_name ?mission_name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Space_Reporters } }
  FILTER(?nf = ?total)
} }
  distributive: { SELECT ?full_name ?mission_name WHERE {
  ?space_reporters_missions a :Space_Reporters_Missions .
  ?missions a :Missions .
  ?space_reporters_missions p:hasMissions ?missions .
  ?space_reporters a :Space_Reporters .
  ?space_reporters_missions p:hasSpace_Reporters ?space_reporters .
  ?space_reporters p:name ?full_name .
  ?missions p:mission_name ?mission_name .
} }
}
